1‚Üíimport React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
2‚Üíimport { X, Palette, Link2, Trash2, Type, Plus, Minus, Save, FileDown, Grid3X3, AlignLeft, AlignCenter, AlignRight, Expand, Shrink } from 'lucide-react';
3‚Üí
4‚Üíconst COLORS = [
5‚Üí  '#ff3131', '#ff6b35', '#ffea00', '#39ff14', '#00d2ff', '#a855f7', '#ec4899',
6‚Üí  '#ffffff', '#94a3b8', '#1e293b', '#000000', '#7c3aed', '#06b6d4', '#84cc16',
7‚Üí];
8‚Üí
9‚Üíconst CELL_COLORS = [
10‚Üí  { label: 'Qizil', value: 'rgba(255,49,49,0.25)' },
11‚Üí  { label: 'Yashil', value: 'rgba(57,255,20,0.2)' },
12‚Üí  { label: 'Ko\'k', value: 'rgba(0,210,255,0.2)' },
13‚Üí  { label: 'Sariq', value: 'rgba(255,234,0,0.2)' },
14‚Üí  { label: 'Binafsha', value: 'rgba(168,85,247,0.2)' },
15‚Üí  { label: 'Pushti', value: 'rgba(236,72,153,0.2)' },
16‚Üí  { label: 'Tozalash', value: 'transparent' },
17‚Üí];
18‚Üí
19‚Üíconst FONTS = ['Inter', 'Arial', 'Georgia', 'Courier New', 'Times New Roman'];
20‚Üíconst SIZES = [10, 12, 14, 16, 18, 20, 24, 28, 32];
21‚Üí
22‚Üíconst DEFAULT_ROWS = 30;
23‚Üíconst DEFAULT_COLS = 12;
24‚Üíconst COL_LABELS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
25‚Üí
26‚Üífunction colLabel(c) {
27‚Üí  if (c < 26) return COL_LABELS[c];
28‚Üí  return COL_LABELS[Math.floor(c / 26) - 1] + COL_LABELS[c % 26];
29‚Üí}
30‚Üí
31‚Üífunction cellKey(r, c) {
32‚Üí  return `${r}-${c}`;
33‚Üí}
34‚Üí
35‚Üíconst ExcelTable = ({ initialData, onSave, machines = [] }) => {
36‚Üí  const [rows, setRows] = useState(initialData?.rows || DEFAULT_ROWS);
37‚Üí  const [cols, setCols] = useState(initialData?.cols || DEFAULT_COLS);
38‚Üí  const [cells, setCells] = useState(initialData?.cells || {});
39‚Üí  const [selectedCell, setSelectedCell] = useState(null);
40‚Üí  const [selectedRange, setSelectedRange] = useState(null);
41‚Üí  const [selectionStart, setSelectionStart] = useState(null);
42‚Üí  const [selecting, setSelecting] = useState(false);
43‚Üí  const [contextMenu, setContextMenu] = useState(null);
44‚Üí  const [editMode, setEditMode] = useState(false);
45‚Üí  const [editValue, setEditValue] = useState('');
46‚Üí  const [activePanel, setActivePanel] = useState(null);
47‚Üí  const [title, setTitle] = useState(initialData?.title || 'Yangi Hisobot');
48‚Üí  const [colWidths, setColWidths] = useState(() => {
49‚Üí    const saved = initialData?.colWidths;
50‚Üí    return saved || {};
51‚Üí  });
52‚Üí  const [rowHeights, setRowHeights] = useState(() => {
53‚Üí    const saved = initialData?.rowHeights;
54‚Üí    return saved || {};
55‚Üí  });
56‚Üí  const [autoResize, setAutoResize] = useState(false);
57‚Üí  const [resizing, setResizing] = useState(null);
58‚Üí  const [resizeStart, setResizeStart] = useState(null);
59‚Üí  const tableRef = useRef(null);
60‚Üí  const editRef = useRef(null);
61‚Üí  const measureRef = useRef(null);
62‚Üí
63‚Üí  const getCell = useCallback((r, c) => {
64‚Üí    return cells[cellKey(r, c)] || { value: '', style: {} };
65‚Üí  }, [cells]);
66‚Üí
67‚Üí  const updateCell = useCallback((r, c, updates) => {
68‚Üí    setCells(prev => {
69‚Üí      const key = cellKey(r, c);
70‚Üí      const existing = prev[key] || { value: '', style: {} };
71‚Üí      return { ...prev, [key]: { ...existing, ...updates } };
72‚Üí    });
73‚Üí  }, []);
74‚Üí
75‚Üí  // Measure text width using canvas
76‚Üí  const measureText = useCallback((text, fontSize = 13, fontFamily = 'Inter', fontWeight = 400) => {
77‚Üí    if (!measureRef.current) {
78‚Üí      measureRef.current = document.createElement('canvas').getContext('2d');
79‚Üí    }
80‚Üí    const ctx = measureRef.current;
81‚Üí    ctx.font = `${fontWeight === 700 ? 'bold ' : ''}${fontSize}px ${fontFamily}`;
82‚Üí    return ctx.measureText(text).width;
83‚Üí  }, []);
84‚Üí
85‚Üí  // Auto-resize column based on content
86‚Üí  const autoResizeColumn = useCallback((colIdx) => {
87‚Üí    let maxWidth = 40;
88‚Üí    for (let r = 0; r < rows; r++) {
89‚Üí      const cell = getCell(r, colIdx);
90‚Üí      const val = String(cell.value || '');
91‚Üí      if (!val) continue;
92‚Üí      const fontSize = cell.style?.fontSize || 13;
93‚Üí      const fontWeight = cell.style?.fontWeight || 400;
94‚Üí      const fontFamily = cell.style?.fontFamily || 'Inter';
95‚Üí      const lines = val.split('\n');
96‚Üí      for (const line of lines) {
97‚Üí        const w = measureText(line, fontSize, fontFamily, fontWeight);
98‚Üí        maxWidth = Math.max(maxWidth, w + 16);
99‚Üí      }
100‚Üí    }
101‚Üí    setColWidths(prev => ({ ...prev, [colIdx]: Math.ceil(maxWidth) }));
102‚Üí  }, [rows, getCell, measureText]);
103‚Üí
104‚Üí  // Auto-resize row based on content
105‚Üí  const autoResizeRow = useCallback((rowIdx) => {
106‚Üí    let maxHeight = 36;
107‚Üí    for (let c = 0; c < cols; c++) {
108‚Üí      const cell = getCell(rowIdx, c);
109‚Üí      const val = String(cell.value || '');
110‚Üí      if (!val) continue;
111‚Üí      const fontSize = cell.style?.fontSize || 13;
112‚Üí      const lines = val.split('\n');
113‚Üí      const cellWidth = colWidths[c] || 80;
114‚Üí      let totalLines = 0;
115‚Üí      for (const line of lines) {
116‚Üí        const w = measureText(line, fontSize, cell.style?.fontFamily || 'Inter', cell.style?.fontWeight || 400);
117‚Üí        totalLines += Math.max(1, Math.ceil(w / (cellWidth - 12)));
118‚Üí      }
119‚Üí      const h = totalLines * (fontSize + 4) + 16;
120‚Üí      maxHeight = Math.max(maxHeight, h);
121‚Üí    }
122‚Üí    setRowHeights(prev => ({ ...prev, [rowIdx]: Math.ceil(maxHeight) }));
123‚Üí  }, [cols, getCell, colWidths, measureText]);
124‚Üí
125‚Üí  // Auto-resize all
126‚Üí  const autoResizeAll = useCallback(() => {
127‚Üí    for (let c = 0; c < cols; c++) autoResizeColumn(c);
128‚Üí    for (let r = 0; r < rows; r++) autoResizeRow(r);
129‚Üí  }, [cols, rows, autoResizeColumn, autoResizeRow]);
130‚Üí
131‚Üí  // When auto-resize is on and cells change, resize all
132‚Üí  useEffect(() => {
133‚Üí    if (autoResize) {
134‚Üí      autoResizeAll();
135‚Üí    }
136‚Üí  }, [cells, autoResize, autoResizeAll]);
137‚Üí
138‚Üí  const getSelectedCells = useCallback(() => {
139‚Üí    if (selectedRange) {
140‚Üí      const res = [];
141‚Üí      const r1 = Math.min(selectedRange.r1, selectedRange.r2);
142‚Üí      const r2 = Math.max(selectedRange.r1, selectedRange.r2);
143‚Üí      const c1 = Math.min(selectedRange.c1, selectedRange.c2);
144‚Üí      const c2 = Math.max(selectedRange.c1, selectedRange.c2);
145‚Üí      for (let r = r1; r <= r2; r++) {
146‚Üí        for (let c = c1; c <= c2; c++) {
147‚Üí          res.push({ r, c });
148‚Üí        }
149‚Üí      }
150‚Üí      return res;
151‚Üí    }
152‚Üí    if (selectedCell) return [selectedCell];
153‚Üí    return [];
154‚Üí  }, [selectedCell, selectedRange]);
155‚Üí
156‚Üí  const handleCellClick = (r, c, e) => {
157‚Üí    if (e.shiftKey && selectedCell) {
158‚Üí      setSelectedRange({
159‚Üí        r1: selectedCell.r, c1: selectedCell.c,
160‚Üí        r2: r, c2: c
161‚Üí      });
162‚Üí      setSelectedCell(null);
163‚Üí    } else {
164‚Üí      setSelectedCell({ r, c });
165‚Üí      setSelectedRange(null);
166‚Üí    }
167‚Üí    setContextMenu(null);
168‚Üí    setActivePanel(null);
169‚Üí  };
170‚Üí
171‚Üí  const handleCellMouseDown = (r, c, e) => {
172‚Üí    if (e.button === 0 && !e.shiftKey) {
173‚Üí      setSelecting(true);
174‚Üí      setSelectionStart({ r, c });
175‚Üí    }
176‚Üí  };
177‚Üí
178‚Üí  const handleCellMouseEnter = (r, c) => {
179‚Üí    if (selecting && selectionStart) {
180‚Üí      setSelectedCell(null);
181‚Üí      setSelectedRange({
182‚Üí        r1: selectionStart.r, c1: selectionStart.c,
183‚Üí        r2: r, c2: c
184‚Üí      });
185‚Üí    }
186‚Üí  };
187‚Üí
188‚Üí  const handleMouseUp = () => {
189‚Üí    setSelecting(false);
190‚Üí    setSelectionStart(null);
191‚Üí    if (resizing) {
192‚Üí      setResizing(null);
193‚Üí      setResizeStart(null);
194‚Üí    }
195‚Üí  };
196‚Üí
197‚Üí  useEffect(() => {
198‚Üí    document.addEventListener('mouseup', handleMouseUp);
199‚Üí    return () => document.removeEventListener('mouseup', handleMouseUp);
200‚Üí  }, []);
201‚Üí
202‚Üí  const handleCellDoubleClick = (r, c) => {
203‚Üí    const cell = getCell(r, c);
204‚Üí    setEditValue(cell.value || '');
205‚Üí    setEditMode(true);
206‚Üí    setTimeout(() => editRef.current?.focus(), 10);
207‚Üí  };
208‚Üí
209‚Üí  const handleEditFinish = () => {
210‚Üí    if (selectedCell) {
211‚Üí      updateCell(selectedCell.r, selectedCell.c, { value: editValue });
212‚Üí    }
213‚Üí    setEditMode(false);
214‚Üí  };
215‚Üí
216‚Üí  const handleContextMenu = (r, c, e) => {
217‚Üí    e.preventDefault();
218‚Üí    setSelectedCell({ r, c });
219‚Üí    setSelectedRange(null);
220‚Üí    setContextMenu({
221‚Üí      x: Math.min(e.clientX, window.innerWidth - 220),
222‚Üí      y: Math.min(e.clientY, window.innerHeight - 300),
223‚Üí    });
224‚Üí  };
225‚Üí
226‚Üí  const handleKeyDown = (e) => {
227‚Üí    if (!selectedCell) return;
228‚Üí    if (editMode) {
229‚Üí      if (e.key === 'Enter' && !e.shiftKey) { handleEditFinish(); e.preventDefault(); }
230‚Üí      if (e.key === 'Escape') { setEditMode(false); e.preventDefault(); }
231‚Üí      return;
232‚Üí    }
233‚Üí    let { r, c } = selectedCell;
234‚Üí    if (e.key === 'ArrowUp') r = Math.max(0, r - 1);
235‚Üí    else if (e.key === 'ArrowDown') r = Math.min(rows - 1, r + 1);
236‚Üí    else if (e.key === 'ArrowLeft') c = Math.max(0, c - 1);
237‚Üí    else if (e.key === 'ArrowRight') c = Math.min(cols - 1, c + 1);
238‚Üí    else if (e.key === 'Enter') { handleCellDoubleClick(r, c); return; }
239‚Üí    else if (e.key === 'Delete' || e.key === 'Backspace') {
240‚Üí      getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '' }));
241‚Üí      return;
242‚Üí    } else if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) {
243‚Üí      setEditValue(e.key);
244‚Üí      setEditMode(true);
245‚Üí      setTimeout(() => editRef.current?.focus(), 10);
246‚Üí      return;
247‚Üí    } else return;
248‚Üí    e.preventDefault();
249‚Üí    setSelectedCell({ r, c });
250‚Üí    setSelectedRange(null);
251‚Üí  };
252‚Üí
253‚Üí  // Column resize
254‚Üí  const handleColResizeStart = (colIdx, e) => {
255‚Üí    e.stopPropagation();
256‚Üí    e.preventDefault();
257‚Üí    setResizing({ type: 'col', index: colIdx });
258‚Üí    setResizeStart({ x: e.clientX, y: e.clientY, origSize: colWidths[colIdx] || 80 });
259‚Üí  };
260‚Üí
261‚Üí  // Row resize
262‚Üí  const handleRowResizeStart = (rowIdx, e) => {
263‚Üí    e.stopPropagation();
264‚Üí    e.preventDefault();
265‚Üí    setResizing({ type: 'row', index: rowIdx });
266‚Üí    setResizeStart({ x: e.clientX, y: e.clientY, origSize: rowHeights[rowIdx] || 36 });
267‚Üí  };
268‚Üí
269‚Üí  useEffect(() => {
270‚Üí    if (!resizing || !resizeStart) return;
271‚Üí    const handleMouseMove = (e) => {
272‚Üí      if (resizing.type === 'col') {
273‚Üí        const delta = e.clientX - resizeStart.x;
274‚Üí        const newWidth = Math.max(30, resizeStart.origSize + delta);
275‚Üí        setColWidths(prev => ({ ...prev, [resizing.index]: newWidth }));
276‚Üí      } else {
277‚Üí        const delta = e.clientY - resizeStart.y;
278‚Üí        const newHeight = Math.max(20, resizeStart.origSize + delta);
279‚Üí        setRowHeights(prev => ({ ...prev, [resizing.index]: newHeight }));
280‚Üí      }
281‚Üí    };
282‚Üí    const handleMouseUp2 = () => {
283‚Üí      setResizing(null);
284‚Üí      setResizeStart(null);
285‚Üí    };
286‚Üí    document.addEventListener('mousemove', handleMouseMove);
287‚Üí    document.addEventListener('mouseup', handleMouseUp2);
288‚Üí    return () => {
289‚Üí      document.removeEventListener('mousemove', handleMouseMove);
290‚Üí      document.removeEventListener('mouseup', handleMouseUp2);
291‚Üí    };
292‚Üí  }, [resizing, resizeStart]);
293‚Üí
294‚Üí  const applyStyleToSelection = (styleUpdate) => {
295‚Üí    getSelectedCells().forEach(({ r, c }) => {
296‚Üí      const cell = getCell(r, c);
297‚Üí      updateCell(r, c, { style: { ...cell.style, ...styleUpdate } });
298‚Üí    });
299‚Üí    setActivePanel(null);
300‚Üí    setContextMenu(null);
301‚Üí  };
302‚Üí
303‚Üí  const deleteCells = () => {
304‚Üí    getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '', style: {} }));
305‚Üí    setContextMenu(null);
306‚Üí  };
307‚Üí
308‚Üí  const addRow = () => setRows(prev => prev + 5);
309‚Üí  const removeRow = () => setRows(prev => Math.max(5, prev - 1));
310‚Üí  const addCol = () => setCols(prev => prev + 2);
311‚Üí  const removeCol = () => setCols(prev => Math.max(3, prev - 1));
312‚Üí
313‚Üí  const linkToMachine = (machineId) => {
314‚Üí    if (selectedCell) {
315‚Üí      updateCell(selectedCell.r, selectedCell.c, {
316‚Üí        linkedMachine: machineId,
317‚Üí        value: `stanok:${machineId}`,
318‚Üí      });
319‚Üí    }
320‚Üí    setActivePanel(null);
321‚Üí    setContextMenu(null);
322‚Üí  };
323‚Üí
324‚Üí  const unlinkMachine = () => {
325‚Üí    if (selectedCell) {
326‚Üí      updateCell(selectedCell.r, selectedCell.c, {
327‚Üí        linkedMachine: null,
328‚Üí        value: '',
329‚Üí      });
330‚Üí    }
331‚Üí    setContextMenu(null);
332‚Üí  };
333‚Üí
334‚Üí  const getCurrentShift = () => {
335‚Üí    const now = new Date();
336‚Üí    const hour = now.getHours();
337‚Üí    if (hour >= 7 && hour < 19) return { type: 'KUNDUZ', label: 'Kunduzgi', shift: 1 };
338‚Üí    return { type: 'TUN', label: 'Tungi', shift: 2 };
339‚Üí  };
340‚Üí
341‚Üí  const renderCellValue = (r, c) => {
342‚Üí    const cell = getCell(r, c);
343‚Üí    if (cell.linkedMachine) {
344‚Üí      const machine = machines.find(m => m.id === cell.linkedMachine);
345‚Üí      const shift = getCurrentShift();
346‚Üí      const meters = machine ? (machine.shift_meters || 0).toFixed(1) : '0.0';
347‚Üí      const statusColor = machine?.status === 'RUNNING' ? '#39ff14' : machine?.status === 'OFFLINE' ? '#ff3131' : '#ffea00';
348‚Üí      return (
349‚Üí        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2px', lineHeight: 1.2 }}>
350‚Üí          <span style={{ fontSize: '0.6rem', fontWeight: 800, color: statusColor }}>{cell.linkedMachine}</span>
351‚Üí          <span style={{ fontSize: '0.75rem', fontWeight: 700, color: '#fff' }}>{meters}m</span>
352‚Üí          <span style={{ fontSize: '0.5rem', color: '#94a3b8', fontWeight: 600 }}>{shift.label}</span>
353‚Üí        </div>
354‚Üí      );
355‚Üí    }
356‚Üí    return cell.value;
357‚Üí  };
358‚Üí
359‚Üí  const getCellStyle = (r, c) => {
360‚Üí    const cell = getCell(r, c);
361‚Üí    const isSelected = (selectedCell && selectedCell.r === r && selectedCell.c === c) ||
362‚Üí      (selectedRange && r >= Math.min(selectedRange.r1, selectedRange.r2) &&
363‚Üí        r <= Math.max(selectedRange.r1, selectedRange.r2) &&
364‚Üí        c >= Math.min(selectedRange.c1, selectedRange.c2) &&
365‚Üí        c <= Math.max(selectedRange.c1, selectedRange.c2));
366‚Üí
367‚Üí    return {
368‚Üí      background: isSelected ? 'rgba(0, 210, 255, 0.15)' : (cell.style?.background || 'transparent'),
369‚Üí      border: isSelected ? '2px solid var(--primary)' : '1px solid rgba(255,255,255,0.06)',
370‚Üí      color: cell.style?.color || '#f8fafc',
371‚Üí      fontWeight: cell.style?.fontWeight || 400,
372‚Üí      fontStyle: cell.style?.fontStyle || 'normal',
373‚Üí      textDecoration: cell.style?.textDecoration || 'none',
374‚Üí      fontSize: cell.style?.fontSize ? `${cell.style.fontSize}px` : '0.8rem',
375‚Üí      fontFamily: cell.style?.fontFamily || 'Inter',
376‚Üí      textAlign: cell.style?.textAlign || 'center',
377‚Üí    };
378‚Üí  };
379‚Üí
380‚Üí  const handleSave = () => {
381‚Üí    const data = { rows, cols, cells, title, colWidths, rowHeights };
382‚Üí    if (onSave) onSave(data);
383‚Üí  };
384‚Üí
385‚Üí  const handleExportPDF = () => {
386‚Üí    if (onSave) onSave({ rows, cols, cells, title, colWidths, rowHeights, exportPDF: true });
387‚Üí  };
388‚Üí
389‚Üí  return (
390‚Üí    <div
391‚Üí      style={{ display: 'flex', flexDirection: 'column', height: '100%', position: 'relative' }}
392‚Üí      onKeyDown={handleKeyDown}
393‚Üí      tabIndex={0}
394‚Üí    >
395‚Üí      {/* Toolbar */}
396‚Üí      <div style={{
397‚Üí        display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 12px',
398‚Üí        background: 'rgba(15,23,42,0.8)', borderBottom: '1px solid rgba(255,255,255,0.08)',
399‚Üí        flexWrap: 'wrap', flexShrink: 0
400‚Üí      }}>
401‚Üí        <input
402‚Üí          value={title}
403‚Üí          onChange={e => setTitle(e.target.value)}
404‚Üí          style={{
405‚Üí            background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
406‚Üí            borderRadius: '8px', padding: '6px 12px', color: '#f8fafc', fontSize: '0.9rem',
407‚Üí            fontWeight: 700, outline: 'none', width: '200px'
408‚Üí          }}
409‚Üí          placeholder="Sarlavha"
410‚Üí        />
411‚Üí
412‚Üí        <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.1)', margin: '0 4px' }} />
413‚Üí
414‚Üí        <ToolBtn icon={<Plus size={14} />} onClick={addRow} title="Qator qo'shish" />
415‚Üí        <ToolBtn icon={<Minus size={14} />} onClick={removeRow} title="Qator olib tashlash" />
416‚Üí        <ToolBtn icon={<Plus size={14} />} onClick={addCol} title="Ustun qo'shish" label="U" />
417‚Üí        <ToolBtn icon={<Minus size={14} />} onClick={removeCol} title="Ustun olib tashlash" label="U" />
